'use strict';

const crypto = require('crypto');

// ============================================
//  Custom Multi-Cipher Morse System
//  303 Versi Cipher - Per-Character Random
//  Semua data terenkripsi AES-256-CBC
// ============================================

const SECRET_PASSPHRASE = "fery-morse-secure-passphrase-2026";
const SALT = "fery-salt-12345";
const KEY = crypto.scryptSync(SECRET_PASSPHRASE, SALT, 32);

// ── Database lama (V1) untuk backward compatibility dekripsi pesan tersimpan ──
const ENCRYPTED_DATABASE = "dd267c34168664879061e1ce7cfd7aaf:";

// ── Database baru: 303 versi cipher terenkripsi AES-256-CBC ──
const ENCRYPTED_ALL_CIPHERS = "dafb8eb748493cd3df896d2c745ea4a3:";

/**
 * Dekripsi teks menggunakan AES-256-CBC
 */
function decryptData(encryptedText) {
  const parts = encryptedText.split(':');
  if (parts.length !== 2 || !parts[0] || !parts[1]) {
    throw new Error('Format data terenkripsi tidak valid');
  }
  const iv = Buffer.from(parts[0], 'hex');
  const decipher = crypto.createDecipheriv('aes-256-cbc', KEY, iv);
  let decrypted = decipher.update(parts[1], 'hex', 'utf8');
  decrypted += decipher.final('utf8');
  return decrypted;
}

/**
 * Parse satu blok cipher dari konten teks
 * Return: { version, symbols: string[], map: {char->code}, reverseMap: {code->char}, spaceCode, symbolSet: Set }
 */
function parseCipherBlock(blockLines) {
  const result = {
    version: 0,
    symbols: [],
    symbolSet: new Set(),
    map: {},
    reverseMap: {},
    spaceCode: ''
  };

  let inMapping = false;

  for (const rawLine of blockLines) {
    const line = rawLine.trim();
    if (!line) continue;

    // Cari nomor versi
    const versionMatch = line.match(/^RANDOM MORSE CIPHER V(\d+)/);
    if (versionMatch) {
      result.version = parseInt(versionMatch[1]);
      continue;
    }

    // Cari baris simbol (setelah "SIMBOL YANG DIGUNAKAN:")
    if (line === 'SIMBOL YANG DIGUNAKAN:') {
      inMapping = true;
      continue;
    }

    // Baris simbol adalah baris setelah header "SIMBOL YANG DIGUNAKAN:"
    if (inMapping && result.symbols.length === 0 && !line.startsWith('-') && !line.startsWith('=')) {
      // Simbol dipisahkan spasi
      const syms = line.split(/\s+/).filter(s => s.length > 0);
      if (syms.length >= 2) {
        result.symbols = syms;
        result.symbolSet = new Set([...syms.join('')]);
        inMapping = false;
      }
      continue;
    }

    // Hentikan parsing mapping di bagian CONTOH
    if (line.includes('CONTOH')) break;

    // Skip separator lines
    if (line.startsWith('=') || line.startsWith('-')) continue;
    if (line === 'HURUF BESAR (A-Z)' || line === 'HURUF KECIL (a-z)' || line === 'ANGKA' || line === 'SIMBOL' || line === 'SPASI') continue;

    // Parse format "CHAR = CODE"
    const match = line.match(/^(.+?)\s*=\s*(.+)$/);
    if (match) {
      const char = match[1].trim();
      const code = match[2].trim();
      if (char === 'SPACE') {
        result.spaceCode = code;
        result.map[' '] = code;
        result.reverseMap[code] = ' ';
      } else if (char.length === 1) {
        result.map[char] = code;
        result.reverseMap[code] = char;
      }
    }
  }

  return result;
}

/**
 * Parse semua 303 cipher dari teks yang sudah didekripsi
 */
function parseAllCiphersFromText(content) {
  const allCiphers = [];
  const lines = content.split('\n');

  let blockStart = -1;
  let inBlock = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    if (line.match(/^RANDOM MORSE CIPHER V\d+/)) {
      if (inBlock && blockStart >= 0) {
        const blockLines = lines.slice(blockStart, i);
        const cipher = parseCipherBlock(blockLines);
        if (cipher.version > 0 && cipher.symbols.length > 0 && Object.keys(cipher.map).length > 0) {
          allCiphers.push(cipher);
        }
      }
      blockStart = i;
      inBlock = true;
    }
  }

  // Parse blok terakhir
  if (inBlock && blockStart >= 0) {
    const blockLines = lines.slice(blockStart);
    const cipher = parseCipherBlock(blockLines);
    if (cipher.version > 0 && cipher.symbols.length > 0 && Object.keys(cipher.map).length > 0) {
      allCiphers.push(cipher);
    }
  }

  return allCiphers;
}

// ── Cache: 303 cipher di-load sekali saat startup ──
let _allCiphers = null;
let _symbolCharIndex = null; // Map: character -> [cipher indices]

/**
 * Inisialisasi dan cache semua 303 cipher versi
 */
function getAllCiphers() {
  if (_allCiphers) return _allCiphers;

  let content = '';
  try {
    content = decryptData(ENCRYPTED_ALL_CIPHERS);
  } catch (e) {
    console.error('\n  ❌ Gagal mendekripsi database 303 cipher! Program rusak.');
    process.exit(1);
  }

  _allCiphers = parseAllCiphersFromText(content);

  // ── Filter: hanya cipher yang symbolSet-nya benar-benar disjoint ──
  // Diperlukan agar auto-detect bekerja 100% akurat tanpa ambiguitas
  const safeCiphers = [];
  const usedSymbols = new Set();
  for (const c of _allCiphers) {
    const mySyms = [...c.symbolSet];
    const hasOverlap = mySyms.some(s => usedSymbols.has(s));
    if (!hasOverlap) {
      safeCiphers.push(c);
      mySyms.forEach(s => usedSymbols.add(s));
    }
  }
  _allCiphers = safeCiphers;

  // Bangun index: tiap karakter dalam symbolSet -> array of cipher index
  _symbolCharIndex = new Map();
  for (let i = 0; i < _allCiphers.length; i++) {
    for (const sym of _allCiphers[i].symbolSet) {
      if (!_symbolCharIndex.has(sym)) {
        _symbolCharIndex.set(sym, []);
      }
      _symbolCharIndex.get(sym).push(i);
    }
  }

  console.log(`✅ Multi-Cipher loaded: ${_allCiphers.length} versi cipher siap.`);
  return _allCiphers;
}

/**
 * Auto-detect versi cipher dari sebuah token kode
 * Lihat karakter pertama → cari versi yang punya simbol itu → validasi semua karakter
 */
function identifyCipherForToken(token, allCiphers) {
  if (!token || token.length === 0) return null;
  const tokenChars = [...token]; // spread untuk handle emoji
  const tokenStr = tokenChars.join('');
  const firstChar = tokenChars[0];
  const candidates = _symbolCharIndex ? (_symbolCharIndex.get(firstChar) || []) : [];

  // Pass 1: cari di candidates - cipher yang benar-benar punya token di reverseMap ATAU sebagai spaceCode
  for (const idx of candidates) {
    const cipher = allCiphers[idx];
    const allMatch = tokenChars.every(c => cipher.symbolSet.has(c));
    if (!allMatch) continue;
    // Prioritaskan: token ada di reverseMap ATAU token cocok dengan spaceCode
    if (cipher.reverseMap[token] !== undefined || tokenStr === [...cipher.spaceCode].join('')) {
      return cipher;
    }
  }

  // Pass 2: fallback - cipher yang symbolSet-nya cocok (tanpa cek reverseMap)
  for (const idx of candidates) {
    const cipher = allCiphers[idx];
    const allMatch = tokenChars.every(c => cipher.symbolSet.has(c));
    if (allMatch) return cipher;
  }

  // Pass 3: brute-force seluruh cipher
  for (const cipher of allCiphers) {
    const allMatch = tokenChars.every(c => cipher.symbolSet.has(c));
    if (allMatch) return cipher;
  }

  return null;
}

/**
 * ENKRIPSI MULTI-CIPHER: Setiap karakter dipilihkan versi random dari 303 versi
 * Spasi juga dapat versi random
 */
function encryptMultiCipher(text, allCiphers) {
  const result = [];

  for (const char of text) {
    // Pilih versi random
    const cipher = allCiphers[Math.floor(Math.random() * allCiphers.length)];

    if (char === ' ') {
      if (cipher.spaceCode) {
        result.push(cipher.spaceCode);
      } else {
        // Fallback: cari cipher lain yang punya spaceCode
        const alt = allCiphers.find(c => c.spaceCode);
        if (alt) result.push(alt.spaceCode);
      }
    } else if (cipher.map[char]) {
      result.push(cipher.map[char]);
    } else {
      // Char tidak ada di versi ini, coba cari versi lain yang punya char ini
      const altCipher = allCiphers.find(c => c.map[char]);
      if (altCipher) {
        result.push(altCipher.map[char]);
      } else {
        // Karakter benar-benar tidak dikenali, simpan sebagai hex escape
        const hex = char.charCodeAt(0).toString(16).padStart(4, '0');
        result.push(`<<${hex}>>`);
      }
    }
  }

  return result.join(' ');
}

/**
 * DEKRIPSI MULTI-CIPHER: Auto-detect versi dari tiap token
 */
function decryptMultiCipher(cipherText, allCiphers) {
  const tokens = cipherText.trim().split(/\s+/);
  let result = '';

  for (const token of tokens) {
    if (!token) continue;

    // Handle hex escape <<xxxx>>
    if (token.startsWith('<<') && token.endsWith('>>')) {
      const hex = token.slice(2, -2);
      result += String.fromCharCode(parseInt(hex, 16));
      continue;
    }

    const cipher = identifyCipherForToken(token, allCiphers);
    if (!cipher) {
      console.warn(`  ⚠  Token '${token}' tidak dikenali oleh semua 303 cipher, dilewati.`);
      continue;
    }

    // Cek apakah token adalah spaceCode (compare dengan spread)
    if ([...token].join('') === [...cipher.spaceCode].join('')) {
      result += ' ';
    } else if (cipher.reverseMap[token]) {
      result += cipher.reverseMap[token];
    }
  }

  return result;
}

/**
 * ENKRIPSI FILE MULTI-CIPHER: Per baris, per karakter
 */
function encryptFileMultiCipher(text, allCiphers) {
  const lines = text.split('\n');

  const encryptedLines = lines.map((line) => {
    if (line === '') return '';

    const result = [];
    for (const char of line) {
      const cipher = allCiphers[Math.floor(Math.random() * allCiphers.length)];

      if (char === ' ') {
        if (cipher.spaceCode) {
          result.push(cipher.spaceCode);
        } else {
          const alt = allCiphers.find(c => c.spaceCode);
          if (alt) result.push(alt.spaceCode);
        }
      } else if (cipher.map[char]) {
        result.push(cipher.map[char]);
      } else {
        const altCipher = allCiphers.find(c => c.map[char]);
        if (altCipher) {
          result.push(altCipher.map[char]);
        } else {
          const hex = char.charCodeAt(0).toString(16).padStart(4, '0');
          result.push(`<<${hex}>>`);
        }
      }
    }
    return result.join(' ');
  });

  return encryptedLines.join('\n');
}

/**
 * DEKRIPSI FILE MULTI-CIPHER: Per baris
 */
function decryptFileMultiCipher(cipherText, allCiphers) {
  const lines = cipherText.split('\n');

  const decryptedLines = lines.map((line) => {
    if (line === '') return '';

    const tokens = line.split(/\s+/);
    let result = '';

    for (const token of tokens) {
      if (!token) continue;

      if (token.startsWith('<<') && token.endsWith('>>')) {
        const hex = token.slice(2, -2);
        result += String.fromCharCode(parseInt(hex, 16));
        continue;
      }

      const cipher = identifyCipherForToken(token, allCiphers);
      if (!cipher) continue;

      if ([...token].join('') === [...cipher.spaceCode].join('')) {
        result += ' ';
      } else if (cipher.reverseMap[token]) {
        result += cipher.reverseMap[token];
      }
    }

    return result;
  });

  return decryptedLines.join('\n');
}

// ============================================================
//  LEGACY FUNCTIONS (untuk backward compatibility pesan lama)
// ============================================================

function parseMorseFile() {
  let content = '';
  try {
    content = decryptData(ENCRYPTED_DATABASE);
  } catch (e) {
    console.error('\n  ❌ Gagal mendekripsi database internal! Program rusak.');
    process.exit(1);
  }

  const lines = content.split('\n');
  const morseMap = {};

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    if (trimmed.includes('CONTOH')) break;
    if (trimmed.startsWith('=')) continue;
    if (trimmed.startsWith('-')) continue;

    const match = trimmed.match(/^(.+?)\s*=\s*(.+)$/);
    if (match) {
      const char = match[1].trim();
      const code = match[2].trim();
      if (char === 'SPACE') {
        morseMap[' '] = code;
      } else if (char.length === 1) {
        morseMap[char] = code;
      }
    }
  }

  return morseMap;
}

function buildReverseMap(morseMap) {
  const reverseMap = {};
  for (const [char, code] of Object.entries(morseMap)) {
    reverseMap[code] = char;
  }
  return reverseMap;
}

function encrypt(text, morseMap) {
  const spaceCode = morseMap[' '] || '!!!!!!!!';
  const result = [];
  for (const char of text) {
    if (char === ' ') {
      result.push(spaceCode);
    } else if (morseMap[char]) {
      result.push(morseMap[char]);
    }
  }
  return result.join(' ');
}

function decrypt(cipherText, morseMap) {
  const reverseMap = buildReverseMap(morseMap);
  const spaceCode = morseMap[' '] || '!!!!!!!!';
  const codes = cipherText.trim().split(/\s+/);
  let result = '';
  for (const code of codes) {
    if (code === spaceCode) {
      result += ' ';
    } else if (reverseMap[code]) {
      result += reverseMap[code];
    }
  }
  return result;
}

function encryptFile(text, morseMap) {
  const spaceCode = morseMap[' '] || '!!!!!!!!';
  const lines = text.split('\n');
  const encryptedLines = lines.map((line) => {
    if (line === '') return '';
    const result = [];
    for (const char of line) {
      if (char === ' ') {
        result.push(spaceCode);
      } else if (morseMap[char]) {
        result.push(morseMap[char]);
      } else {
        const hex = char.charCodeAt(0).toString(16).padStart(4, '0');
        result.push(`<<${hex}>>`);
      }
    }
    return result.join(' ');
  });
  return encryptedLines.join('\n');
}

function decryptFile(cipherText, morseMap) {
  const reverseMap = buildReverseMap(morseMap);
  const spaceCode = morseMap[' '] || '!!!!!!!!';
  const lines = cipherText.split('\n');
  const decryptedLines = lines.map((line) => {
    if (line === '') return '';
    const codes = line.split(/\s+/);
    let result = '';
    for (const code of codes) {
      if (!code) continue;
      if (code === spaceCode) {
        result += ' ';
      } else if (code.startsWith('<<') && code.endsWith('>>')) {
        const hex = code.slice(2, -2);
        result += String.fromCharCode(parseInt(hex, 16));
      } else if (reverseMap[code]) {
        result += reverseMap[code];
      }
    }
    return result;
  });
  return decryptedLines.join('\n');
}

module.exports = {
  // ── Baru: Multi-cipher (per-character random) ──
  getAllCiphers,
  encryptMultiCipher,
  decryptMultiCipher,
  encryptFileMultiCipher,
  decryptFileMultiCipher,

  // ── Legacy (backward compatibility) ──
  parseMorseFile,
  buildReverseMap,
  encrypt,
  decrypt,
  encryptFile,
  decryptFile
};
